#!/usr/bin/env bash
set -Eeuo pipefail
EXPECTED_SHA256="98d8693717a0245c05008dfca201e77cf0d552d2e565e1eb7156e5be6a004ed8"
PAYLOAD_BYTES="2356249"
MARKER="__VELORAOS_184_PAYLOAD__"
TMPDIR="$(mktemp -d /tmp/veloraos-1.8.4-package.XXXXXX)"
cleanup(){ rm -rf "$TMPDIR"; }
trap cleanup EXIT INT TERM
[[ ${EUID:-$(id -u)} -eq 0 ]] || { echo 'Run this script with sudo.' >&2; exit 1; }
for command in awk base64 tr sha256sum stat tar; do command -v "$command" >/dev/null 2>&1 || { echo "Required command is missing: $command" >&2; exit 1; }; done
PAYLOAD_FILE="$TMPDIR/payload.tar.gz"
awk -v marker="$MARKER" '{line=$0; sub(/\r$/, "", line)} line==marker{found=1;next}found{print}END{if(!found)exit 2}' "$0" \
  | tr -d '[:space:]' \
  | base64 --decode > "$PAYLOAD_FILE" \
  || { echo 'Installer payload is missing or is not valid Base64. Download the raw script rather than copying it through an editor.' >&2; exit 1; }
[[ "$(stat -c '%s' "$PAYLOAD_FILE")" == "$PAYLOAD_BYTES" ]] || { echo 'Installer payload size check failed.' >&2; exit 1; }
[[ "$(sha256sum "$PAYLOAD_FILE" | awk '{print $1}')" == "$EXPECTED_SHA256" ]] || { echo 'Installer payload integrity check failed.' >&2; exit 1; }
tar -tzf "$PAYLOAD_FILE" >/dev/null || { echo 'Installer payload archive validation failed.' >&2; exit 1; }
tar -xzf "$PAYLOAD_FILE" -C "$TMPDIR"
exec "$TMPDIR/veloraos-1.8.4/installer/veloraos-install.sh" "$@"
exit 1
